  1	import * as React from 'react';
  2	
  3	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
  4	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
  5	import DeprecatedBadge from '@kubevirt-utils/components/badges/DeprecatedBadge/DeprecatedBadge';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import {
  8	  getTemplateFlavorData,
  9	  isDeprecatedTemplate,
 10	  WORKLOADS_LABELS,
 11	} from '@kubevirt-utils/resources/template';
 12	import { getTemplateBootSourceType } from '@kubevirt-utils/resources/template/hooks/useVmTemplateSource/utils';
 13	import {
 14	  getTemplateName,
 15	  getTemplateWorkload,
 16	} from '@kubevirt-utils/resources/template/utils/selectors';
 17	import { getVMBootSourceLabel } from '@kubevirt-utils/resources/vm/utils/source';
 18	import { readableSizeUnit } from '@kubevirt-utils/utils/units';
 19	import { CatalogTile } from '@patternfly/react-catalog-view-extension';
 20	import { Badge, Skeleton, Stack, StackItem } from '@patternfly/react-core';
 21	
 22	import { getTemplateOSIcon } from '../utils/os-icons';
 23	
 24	export type TemplateTileProps = {
 25	  availableDatasources: Record<string, V1beta1DataSource>;
 26	  availableTemplatesUID: Set<string>;
 27	  bootSourcesLoaded: boolean;
 28	  isSelected?: boolean;
 29	  onClick: (template: V1Template) => void;
 30	  template: V1Template;
 31	};
 32	
 33	export const TemplateTile: React.FC<TemplateTileProps> = React.memo(
 34	  ({ availableDatasources, availableTemplatesUID, bootSourcesLoaded, onClick, template }) => {
 35	    const { t } = useKubevirtTranslation();
 36	
 37	    const isDeprecated = isDeprecatedTemplate(template);
 38	    const workload = getTemplateWorkload(template);
 39	    const displayName = getTemplateName(template);
 40	    const bootSource = getTemplateBootSourceType(template);
 41	    const isBootSourceAvailable = availableTemplatesUID.has(template.metadata.uid);
 42	    const dataSource =
 43	      availableDatasources[
 44	        `${bootSource?.source?.sourceRef?.namespace}-${bootSource?.source?.sourceRef?.name}`
 45	      ];
 46	    const { cpuCount, memory } = getTemplateFlavorData(template);
 47	
 48	    const icon = React.useMemo(() => {
 49	      return getTemplateOSIcon(template);
 50	      // eslint-disable-next-line react-hooks/exhaustive-deps
 51	    }, [template?.metadata?.annotations?.iconClass]);
 52	
 53	    return (
 54	      <div onClick={() => onClick(template)}>
 55	        <CatalogTile
 56	          badges={[
 57	            <Stack className="badge-stack" key="badge-stack">
 58	              {bootSourcesLoaded
 59	                ? isBootSourceAvailable && [
 60	                    <Badge key="available-boot">{t('Source available')}</Badge>,
 61	                  ]
 62	                : [
 63	                    <Skeleton
 64	                      className="badgeload"
 65	                      height="18px"
 66	                      key="loading-sources"
 67	                      width="105px"
 68	                    />,
 69	                  ]}
 70	              {isDeprecated ? <DeprecatedBadge className="deprecated-template" /> : null}
 71	            </Stack>,
 72	          ]}
 73	          title={
 74	            <Stack>
 75	              <StackItem>
 76	                <b>{displayName}</b>
 77	              </StackItem>
 78	              <StackItem className="text-secondary">{template.metadata.name}</StackItem>
 79	            </Stack>
 80	          }
 81	          className="vm-catalog-grid-tile"
 82	          data-test-id={template.metadata.name}
 83	          iconImg={icon}
 84	        >
 85	          <Stack hasGutter>
 86	            <StackItem>
 87	              <Stack>
 88	                <StackItem>
 89	                  <b>{t('Project')}</b> {template.metadata.namespace}
 90	                </StackItem>
 91	                <StackItem>
 92	                  <b>{t('Boot source')}</b> {getVMBootSourceLabel(bootSource?.type, dataSource)}
 93	                </StackItem>
 94	                <StackItem>
 95	                  <b>{t('Workload')}</b> {WORKLOADS_LABELS?.[workload] ?? t('Other')}
 96	                </StackItem>
 97	                <StackItem>
 98	                  <StackItem>
 99	                    <b>{t('CPU')}</b> {cpuCount}
100	                  </StackItem>
101	                  <StackItem>
102	                    <b>{t('Memory')}</b> {readableSizeUnit(memory)}
103	                  </StackItem>
104	                </StackItem>
105	              </Stack>
106	            </StackItem>
107	          </Stack>
108	        </CatalogTile>
109	      </div>
110	    );
111	  },
112	);

